using System;

[AttributeUsage(AttributeTargets.All)]
public class TypeAttr : Attribute
{
    public TypeAttr(string description) { Description = description; }
    public string Description { get; }
}

[TypeAttr("user service")]
public interface IUserService
{
    string GetUserName(int id);
}

[YS.Knife.ExposeApi(typeof(IUserService), TypeAttributePatterns = new string[] { "TypeAttr" })]
